import { Box, Flex, Grid, Text, Heading } from "@chakra-ui/react";
import React from "react";
import { Bar, Line, Pie } from "react-chartjs-2";
import AdminNavTop from "../AdminNavTop";

const Statistics = () => {
  const data = {
    labels: ["Jan", "Feb", "Mar", "Apr", "May", "Jun"],
    datasets: [
      {
        label: "Subscribers",
        data: [100, 200, 150, 250, 300, 200],
        borderColor: "#A435F0",
        backgroundColor: "rgba(164, 53, 240, 0.1)",
        tension: 0.4,
      },
    ],
  };

  const datapie1 = {
    labels: ["Full Stack", "Frontend", "Backend"],
    datasets: [
      {
        data: [300, 50, 100],
        backgroundColor: ["#A435F0", "#d1a3ff", "#ede5ff"],
      },
    ],
  };

  const databar = {
    labels: ["Jan", "Feb", "Mar", "Apr", "May", "Jun"],
    datasets: [
      {
        label: "Courses",
        data: [12, 19, 3, 5, 2, 3],
        backgroundColor: "#A435F0",
      },
    ],
  };

  return (
    <Box bg="#f7f9fa" minH="100vh">
      <AdminNavTop />

      <Box maxW="1200px" mx="auto" p={6}>
        <Heading size="lg" mb={6}>
          Dashboard Analytics
        </Heading>

        {/* Top Charts */}
        <Grid
          templateColumns={{
            base: "1fr",
            md: "1fr 1fr",
          }}
          gap={6}
        >
          {/* Line Chart */}
          <Box
            bg="white"
            p={5}
            borderRadius="lg"
            boxShadow="sm"
          >
            <Text fontWeight="600" mb={3}>
              User Growth
            </Text>
            <Box h="300px">
              <Line data={data} options={{ maintainAspectRatio: false }} />
            </Box>
          </Box>

          {/* Pie Chart */}
          <Box
            bg="white"
            p={5}
            borderRadius="lg"
            boxShadow="sm"
          >
            <Text fontWeight="600" mb={3}>
              Course Distribution
            </Text>
            <Box h="300px">
              <Pie data={datapie1} options={{ maintainAspectRatio: false }} />
            </Box>
          </Box>
        </Grid>

        {/* Bottom Chart */}
        <Box
          bg="white"
          p={5}
          borderRadius="lg"
          boxShadow="sm"
          mt={6}
        >
          <Text fontWeight="600" mb={3}>
            Monthly Sales
          </Text>
          <Box h="300px">
            <Bar data={databar} options={{ maintainAspectRatio: false }} />
          </Box>
        </Box>
      </Box>
    </Box>
  );
};

export default Statistics;
